use serde::Serialize;
use tokio::process::{Child, Command};
use uuid::Uuid;
use chrono::Local;
use anyhow::{anyhow, Result};
use std::sync::Arc;
use tokio::sync::RwLock;
use tokio::io::{AsyncBufReadExt, BufReader};
use serde_json::json;
use tauri::Emitter;

/// A guarded moonshine shell process.
///
/// The mutable fields (`status`, `exit_code`, `output`) live behind `Arc<RwLock>`
/// so the background reader/waiter tasks can update them after `spawn` returns,
/// and so the clone stored in the process table observes the same live state.
/// The backend is the source of truth for output: live `shell:output` events are
/// only an optimization for streaming. Even if the frontend misses every event
/// (e.g. a fast `echo` that completes before the listener mounts), polling
/// `get_process` recovers the full persisted output and exit code.
#[derive(Clone)]
pub struct ShellProcess {
    pub id: String,
    pub command: String,
    pub created_at: String,
    pub status: Arc<RwLock<String>>,
    pub exit_code: Arc<RwLock<Option<i32>>>,
    pub output: Arc<RwLock<String>>,
    pub child: Arc<RwLock<Option<Child>>>,
}

/// Serializable snapshot of a `ShellProcess` for the frontend.
#[derive(Debug, Clone, Serialize)]
pub struct ShellProcessSnapshot {
    pub id: String,
    pub command: String,
    pub created_at: String,
    pub status: String,
    pub exit_code: Option<i32>,
    pub output: String,
}

impl ShellProcess {
    pub fn new(command: String) -> Self {
        ShellProcess {
            id: Uuid::new_v4().to_string(),
            command,
            created_at: Local::now().to_rfc3339(),
            status: Arc::new(RwLock::new("running".to_string())),
            exit_code: Arc::new(RwLock::new(None)),
            output: Arc::new(RwLock::new(String::new())),
            child: Arc::new(RwLock::new(None)),
        }
    }

    /// Snapshot the live state for serialization to the frontend.
    pub async fn snapshot(&self) -> ShellProcessSnapshot {
        ShellProcessSnapshot {
            id: self.id.clone(),
            command: self.command.clone(),
            created_at: self.created_at.clone(),
            status: self.status.read().await.clone(),
            exit_code: *self.exit_code.read().await,
            output: self.output.read().await.clone(),
        }
    }

    pub async fn kill(&mut self) -> Result<()> {
        let mut child_guard = self.child.write().await;
        if let Some(mut child) = child_guard.take() {
            child.kill().await?;
            *self.status.write().await = "killed".to_string();
            Ok(())
        } else {
            Err(anyhow!("No child process to kill"))
        }
    }
}

fn resolve_monster_guard_bin() -> Result<String> {
    if let Ok(bin) = std::env::var("MONSTER_GUARD_BIN") {
        return Ok(bin);
    }

    which::which("monster-guard")
        .map(|p| p.to_string_lossy().to_string())
        .map_err(|_| anyhow!("monster-guard binary not found in PATH. Set MONSTER_GUARD_BIN env var."))
}

fn resolve_moonshine_bin() -> Result<String> {
    if let Ok(bin) = std::env::var("MOONSHINE_BIN") {
        return Ok(bin);
    }

    which::which("moonshine")
        .map(|p| p.to_string_lossy().to_string())
        .map_err(|_| anyhow!("moonshine binary not found in PATH. Set MOONSHINE_BIN env var."))
}

fn get_monster_guard_home() -> Result<String> {
    if let Ok(home) = std::env::var("MONSTER_GUARD_HOME") {
        return Ok(home);
    }

    let home_dir = home::home_dir()
        .ok_or_else(|| anyhow!("Could not determine home directory"))?;
    let default_home = home_dir.join(".moonshine.d");
    Ok(default_home.to_string_lossy().to_string())
}

async fn delegate_capabilities(session_name: &str, caps: &str) -> Result<()> {
    let guard_bin = resolve_monster_guard_bin()?;
    let guard_home = get_monster_guard_home()?;

    let output = tokio::process::Command::new(&guard_bin)
        .env("MONSTER_GUARD_HOME", &guard_home)
        .args(["delegate", session_name, caps, "--ttl", "3600"])
        .output()
        .await?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(anyhow!("Failed to delegate capabilities: {}", stderr));
    }

    Ok(())
}

pub async fn spawn_guarded_moonshine(
    command: &str,
    #[cfg(not(target_os = "android"))] app: tauri::AppHandle,
) -> Result<ShellProcess> {
    let moonshine_bin = resolve_moonshine_bin()?;
    let guard_bin = resolve_monster_guard_bin()?;
    let guard_home = get_monster_guard_home()?;
    let session_name = format!("moonshine-session-{}", Uuid::new_v4());

    delegate_capabilities(&session_name, "fs,net,exec").await?;

    let mut child = Command::new(&guard_bin)
        .env("MONSTER_GUARD_HOME", &guard_home)
        .args([
            "run",
            "--name",
            &session_name,
            "--caps",
            "fs,net,exec",
            "--lease",
            "3600",
            "--",
            &moonshine_bin,
            "-c",
            command,
        ])
        .stdout(std::process::Stdio::piped())
        .stderr(std::process::Stdio::piped())
        .spawn()?;

    let process = ShellProcess::new(command.to_string());
    let process_id = process.id.clone();

    // Extract stdout/stderr before storing the child handle in the shared slot.
    let stdout = child.stdout.take();
    let stderr = child.stderr.take();

    // Store the child so both the waiter task (which records the exit code) and
    // kill() observe the same handle behind one lock — no ownership race.
    *process.child.write().await = Some(child);

    // Reader task: append each stdout line to the persisted buffer AND emit a
    // live event. Persistence is the source of truth; the event is for liveness.
    #[cfg(not(target_os = "android"))]
    if let Some(stdout_pipe) = stdout {
        let proc_id = process_id.clone();
        let app_handle = app.clone();
        let out_buf = process.output.clone();
        tokio::spawn(async move {
            let reader = BufReader::new(stdout_pipe);
            let mut lines = reader.lines();
            while let Ok(Some(line)) = lines.next_line().await {
                {
                    let mut buf = out_buf.write().await;
                    buf.push_str(&line);
                    buf.push('\n');
                }
                let _ = app_handle.emit(
                    "shell:output",
                    json!({ "process_id": proc_id, "line": line, "stream": "stdout" }),
                );
            }
        });
    }

    #[cfg(not(target_os = "android"))]
    if let Some(stderr_pipe) = stderr {
        let proc_id = process_id.clone();
        let app_handle = app.clone();
        let out_buf = process.output.clone();
        tokio::spawn(async move {
            let reader = BufReader::new(stderr_pipe);
            let mut lines = reader.lines();
            while let Ok(Some(line)) = lines.next_line().await {
                {
                    let mut buf = out_buf.write().await;
                    buf.push_str(&line);
                    buf.push('\n');
                }
                let _ = app_handle.emit(
                    "shell:output",
                    json!({ "process_id": proc_id, "line": line, "stream": "stderr" }),
                );
            }
        });
    }

    // Waiter task: poll the shared child slot with try_wait so kill() can still
    // grab the handle. When the child exits (or kill() removes it), persist the
    // exit code + final status and emit a completion event so the frontend stops
    // showing "running".
    #[cfg(not(target_os = "android"))]
    {
        let child_slot = process.child.clone();
        let status_slot = process.status.clone();
        let exit_slot = process.exit_code.clone();
        let proc_id = process_id.clone();
        let app_handle = app.clone();
        tokio::spawn(async move {
            loop {
                // Poll under the lock, then release it before sleeping so kill()
                // and snapshots aren't blocked.
                let outcome = {
                    let mut guard = child_slot.write().await;
                    // Outer Option = "is it finished?"; inner Option<i32> = exit code.
                    match guard.as_mut() {
                        Some(child) => match child.try_wait() {
                            Ok(Some(exit_status)) => Some(exit_status.code()),
                            Ok(None) => None,              // still running
                            Err(_) => Some(None),          // wait error
                        },
                        None => Some(None),                // taken by kill()
                    }
                };

                match outcome {
                    None => {
                        tokio::time::sleep(std::time::Duration::from_millis(20)).await;
                        continue;
                    }
                    Some(code) => {
                        // Drop the child handle now that it has exited.
                        *child_slot.write().await = None;
                        *exit_slot.write().await = code;
                        {
                            let mut s = status_slot.write().await;
                            // Don't clobber a "killed" status set by kill().
                            if s.as_str() != "killed" {
                                *s = if code.is_some() { "completed" } else { "error" }
                                    .to_string();
                            }
                        }
                        let _ = app_handle.emit(
                            "shell:exit",
                            json!({ "process_id": proc_id, "exit_code": code }),
                        );
                        break;
                    }
                }
            }
        });
    }

    Ok(process)
}
